const items=$input.all();
const out=[];
for (let i=0;i<items.length;i++){
  const it=items[i]; const bin=it.binary||{}; const j=it.json;
  const docs=[];
  for (const key of Object.keys(bin)){
    const b=bin[key]; const mt=(b.mimeType||'').toLowerCase(); const nm=(b.fileName||'').toLowerCase();
    if(mt.includes('pdf')||nm.endsWith('.pdf')){
      const buf=await this.helpers.getBinaryDataBuffer(i,key);
      docs.push({type:'document',source:{type:'base64',media_type:'application/pdf',data:buf.toString('base64')}});
    }
  }
  if(docs.length===0){throw new Error('У листі немає PDF-вкладень.');}
  const textBody=(j.textPlain||j.text||j.textHtml||'').toString();
  function field(label){const re=new RegExp(label+'\\s*[:\uFF1A]\\s*(.+)','i');const m=textBody.match(re);return m?m[1].trim():'';}
  let truck='',trailer='';
  const av=field('\u0410\u0432\u0442\u043e');
  if(av){const p=av.split('/');truck=(p[0]||'').trim();trailer=(p[1]||'').trim();}
  const date=field('\u0414\u0430\u0442\u0430');
  const border=field('\u041f\u0435\u0440\u0435\u0442\u0438\u043d');
  const carrier=field('\u041f\u0435\u0440\u0435\u0432\u0456\u0437\u043d\u0438\u043a');
  function hdr(name){if(Array.isArray(j.headers)){const h=j.headers.find(x=>(x.name||'').toLowerCase()===name);if(h)return h.value;}return j[name]||j[name.charAt(0).toUpperCase()+name.slice(1)]||'';}
  const prompt="Ти обробляєш комерційні документи на морський вантаж. У вкладеннях можуть бути різні документи.\nВИКОРИСТОВУЙ ДАНІ ВИКЛЮЧНО з Bill of Lading (коносамент) та Commercial Invoice (інвойс). Решту ІГНОРУЙ.\nПоверни СТРОГО валідний JSON без пояснень і без markdown, з полями:\n{\n\"sender\":\"відправник (Shipper/Seller): назва та адреса; КОЖНА ЧАСТИНА З НОВОГО РЯДКА через символ \\\\n (назва, потім вулиця, потім місто індекс країна)\",\n\"receiver\":\"отримувач (Consignee): так само, кожна частина з нового рядка через \\\\n\",\n\"delivery_city\":\"МІСТО з адреси ОТРИМУВАЧА (Consignee) — місто кінцевої доставки, напр. DNIPRO. ЦЕ НЕ ПОРТ.\",\n\"delivery_country\":\"КРАЇНА з адреси отримувача, напр. UKRAINE\",\n\"loading\":\"Port of Discharge з Bill of Lading — порт, де судно ВИВАНТАЖУЄ вантаж (напр. GDANSK, POLAND). ЦЕ НЕ Port of Loading і НЕ BUSAN. Формат: МІСТО, КРАЇНА\",\n\"invoice\":\"номер інвойсу (Invoice No.)\",\n\"invoice_date\":\"дата інвойсу у форматі ДД.ММ.РРРР\",\n\"container\":\"номер контейнера\",\n\"packages\":\"кількість місць, лише число (напр. 720)\",\n\"packaging\":\"вид упаковки (напр. BAGS)\",\n\"goods\":\"назва вантажу (напр. ABS RESIN SV-0167)\",\n\"weight\":\"вага БРУТТО (Gross Weight) з одиницею (напр. 18 129,600 KGS)\",\n\"volume\":\"об єм/measurement (напр. 25.92 CBM)\"\n}\nВага — ОБОВ`ЯЗКОВО брутто. Якщо поля немає — постав \"\".";
  const body={model:'claude-sonnet-4-6',max_tokens:1500,messages:[{role:'user',content:docs.concat([{type:'text',text:prompt}])}]};
  out.push({json:{body,truck,trailer,date,border,carrier,from:(j.from&&j.from.value&&j.from.value[0]&&j.from.value[0].address)||hdr('from')||j.from||'',cc:(j.cc&&j.cc.text)||hdr('cc')||'',subject:j.subject||'',messageId:j.messageId||hdr('message-id')||''}});
}
return out;

const resp=$input.item.json;
let text=(resp.content&&Array.isArray(resp.content))?resp.content.map(c=>c.text||'').join(''):(resp.text||'').toString();
text=text.replace(/```json/gi,'').replace(/```/g,'').trim();
let data={};try{data=JSON.parse(text);}catch(e){const mm=text.match(/\{[\s\S]*\}/);if(mm)data=JSON.parse(mm[0]);}
const prep=$('\u041f\u0456\u0434\u0433\u043e\u0442\u043e\u0432\u043a\u0430 \u0434\u0430\u043d\u0438\u0445').item.json;
const f=k=>(data[k]||'').toString().trim();
const container=f('container'); const receiver=f('receiver');
const receiverShort=receiver.split(/[\n,]/)[0].trim();
const docTitle='CMR draft \u2116'+container+' '+receiverShort;
const map={sender:f('sender'),receiver:receiver,delivery_city:f('delivery_city'),delivery_country:f('delivery_country'),loading:f('loading'),invoice:f('invoice'),invoice_date:f('invoice_date'),container:container,packages:f('packages'),packaging:f('packaging'),goods:f('goods'),weight:f('weight'),volume:f('volume'),date:prep.date||'',border:prep.border||'',carrier:prep.carrier||'',truck:prep.truck||'',trailer:prep.trailer||''};
const ph=Object.keys(map).map(k=>['{'+'{'+k+'}'+'}',map[k]]);
const docsBody={requests:ph.map(p=>({replaceAllText:{containsText:{text:p[0],matchCase:true},replaceText:String(p[1]||'')}}))};
return [{json:Object.assign({},map,{docTitle,docsBody,from:prep.from,cc:prep.cc,subject:prep.subject})}];
